using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Look up the value of a configuration key.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up (e.g. 'DatabaseTimeout')")] string key)
    {
        var config = AppConfig.Current;
        return config.TryGetValue(key, out var value)
            ? $"{key} = {value}"
            : $"Key '{key}' not found. Available keys: {string.Join(", ", config.Keys)}";
    }

    [McpServerTool, Description("Update a configuration value at runtime.")]
    public static string SetConfigValue(
        [Description("The configuration key to set")] string key,
        [Description("The new value")] string value)
    {
        AppConfig.Current[key] = value;
        return $"Updated {key} = {value}";
    }

    [McpServerTool, Description("List all available configuration keys.")]
    public static string ListConfigKeys()
    {
        return JsonSerializer.Serialize(AppConfig.Current.Keys, AppConfig.JsonOptions);
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "Application Settings",
        MimeType = "application/json"),
     Description("Returns the full application configuration as JSON.")]
    public static string GetAllSettings()
    {
        return JsonSerializer.Serialize(AppConfig.Current, AppConfig.JsonOptions);
    }

    [McpServerResource(
        UriTemplate = "config://app/version",
        Name = "App Version",
        MimeType = "text/plain"),
     Description("Returns the application version string.")]
    public static string GetVersion()
    {
        return AppConfig.Current.GetValueOrDefault("AppVersion", "0.0.0");
    }
}

using System.Text.Json;

public static class AppConfig
{
    public static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    public static Dictionary<string, string> Current { get; } = new()
    {
        ["AppVersion"] = "1.0.0",
        ["DatabaseTimeout"] = "30",
        ["MaxRetries"] = "3",
        ["LogLevel"] = "Information",
        ["FeatureFlags.DarkMode"] = "true"
    };
}

