var builder = WebApplication.CreateBuilder(args);

builder.Services.AddMcpServer(options =>
    {
        options.ServerInfo = new() { Name = "ConfigMcpServer", Version = "1.0.0" };
        options.ServerInstructions = "Provides application configuration data via tools and resources.";
    })
    .WithHttpTransport()
    .WithToolsFromAssembly()
    .WithResourcesFromAssembly();

var app = builder.Build();

app.MapMcp();
app.MapGet("/health", () => "ok");

app.Run();

